// ─── HELPERS ──────────────────────────────────────────────────────────────────

export const getAllCommunities = (): Community[] =>
  mockBuilders.flatMap((b) => b.communities);

export const getAllIncentives = (): Incentive[] =>
  mockBuilders.flatMap((b) => b.incentives);

export const getBuilderBySlug = (slug: string): Builder | undefined =>
  mockBuilders.find((b) => b.slug === slug);

export const getStats = () => ({
  builders: mockBuilders.length,
  communities: getAllCommunities().length,
  activeIncentives: getAllIncentives().filter((i) => i.active).length,
  citiesServed: [...new Set(getAllCommunities().map((c) => c.city))].length,
});
